const today = new Date().toISOString().split('T')[0];

const habits = [
  { id: 1, name: 'Morning Routine (6h)', icon: 'sun' },
  { id: 2, name: 'Deep Work (3h min)', icon: 'target' },
  { id: 3, name: 'Inbox Zero', icon: 'email' },
  { id: 4, name: 'Sport / Mouvement', icon: 'muscle' },
  { id: 5, name: 'Lecture (30 min)', icon: 'book' },
  { id: 6, name: 'Revue du soir', icon: 'moon' }
];

const timeblocks = [
  { start: '03:30', task: 'Morning Routine', type: 'routine', duration: 45 },
  { start: '04:15', task: 'TaxDome + Emails (Inbox Zero)', type: 'admin', duration: 45 },
  { start: '05:00', task: 'Deep Work - Steuererklaerungen', type: 'deep', duration: 120 },
  { start: '07:00', task: 'Message Reviews', type: 'admin', duration: 120 },
  { start: '09:00', task: 'Deep Work - ELSTER / Dossiers', type: 'deep', duration: 180 },
  { start: '12:00', task: 'Pause dejeuner', type: 'break', duration: 60 },
  { start: '13:00', task: 'Appels und Meetings mandants', type: 'meeting', duration: 120 },
  { start: '15:00', task: 'Admin und Facturation', type: 'admin', duration: 60 },
  { start: '16:00', task: 'Formation / Lecture pro', type: 'learning', duration: 45 },
  { start: '16:45', task: 'Revue du soir und Planification', type: 'routine', duration: 30 }
];

const habitValues = habits.map(h => `('${today}', ${h.id}, '${h.name}', '${h.icon}', false, 0)`).join(', ');
const habitSQL = `INSERT INTO \`wambs-consulting.dashboard_analytics.daily_habits_log\` (date, habit_id, habit_name, icon, completed, streak) VALUES ${habitValues}`;

const tbValues = timeblocks.map(t => `('${today}', '${t.start}', '${t.task}', '${t.type}', ${t.duration})`).join(', ');
const tbSQL = `INSERT INTO \`wambs-consulting.dashboard_analytics.timeblock_tracking\` (date, block_start, task, type, planned_duration) VALUES ${tbValues}`;

const sessionSQL = `INSERT INTO \`wambs-consulting.dashboard_analytics.session_log\` (date, session_start, tasks_completed, files_modified, skills_used, notes) VALUES ('${today}', TIMESTAMP('${today} 03:30:00'), 0, 0, 'n8n-auto-snapshot', 'Automated daily snapshot via n8n')`;

return [
  { json: { habitsSql: habitSQL, timeblocksSql: tbSQL, sessionSql: sessionSQL, today, summary: `Snapshot ${today}: 6 habits, 10 timeblocks, 1 session logged` } }
];
